VALUES
  ('dietitian-moex-01583', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生為心衰竭合併敗血症入住加護病房，醫師確認其血流動力穩定（HemodynamicallyStable） 後，應開始建立灌食路徑時，下列何者觀念較為正確？', '["可經鼻胃管灌，選用2kcal/mL的配方，以每4小時灌50c.c.開始", "經鼻胃管灌後，胃殘餘量>250mL，馬上改為鼻十二指腸管仍繼續灌食", "經鼻胃管灌後顯著腹脹腹硬，仍可繼續灌食", "需直接使用2kcal/mL的配方以鼻十二指腸管灌食"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01584', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生診斷急性胰臟炎併發急性呼吸窘迫症候群，入住加護病房第2天血液動力學穩定後開始連 續管灌時，出現腸胃耐受不良，胃餘量（residual volume）200 ml，請問下一步的營養治療計畫 何者為宜？', '["繼續灌食，給予促腸蠕動藥", "停止灌食，給予全靜脈營養", "停止灌食，給予三合一周邊全靜脈營養", "停止灌食，給予5%葡萄糖靜脈注射"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01585', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列那一項不是促進術後恢復計畫（enhancedrecoveryaftersurgery,ERAS）強調的照護重點？', '["術後的疼痛控制", "術後儘早下床活動", "術後即早以鼻胃管餵食", "術後避免水分過度補充"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01586', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者可做為重症病人肌肉組織直接的能量來源？', '["valine", "alanine", "lysine", "glutamicacid"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01587', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關慢性阻塞性肺病（COPD）患者的營養素需求及補充策略，下列何者錯誤？', '["應有足夠醣類攝取（占總熱量55～65%），以降低呼吸負擔", "避免患者脫水和幫助排痰，應攝取適當的液體，建議30～35毫升/公斤體重", "患者有肺性心臟病（corpulmonale）或水分滯留時，需限鈉和限水", "蛋白質建議攝取應占總熱量15～20%，以維持呼吸和免疫功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01588', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關肺癌惡病質病患營養照護重點之敘述，下列何者錯誤？', '["少量多餐", "脂肪：醣類為1：1之口服補充劑具有較佳耐受性", "足夠熱量至少達到REE為原則", "餐前宜休息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01589', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關接受Hospicecare的癌症末期病人之營養介入措施，下列何者最適當？', '["病人攝食量必須符合營養治療所建議的熱量及蛋白質", "若病人熱量攝入未達建議量，應積極補充靜脈營養", "提供病人喜好的食物，使其生理及心靈上獲得尊重及滿足", "若病人攝食量不足，建議管灌餵食以達到100%DRIs之維生素、礦物質為目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01590', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關口腔及鼻咽癌病人接受放射線治療的副作用，下列何者較不常發生？', '["胃酸逆流", "黏膜炎", "味覺及嗅覺改變", "口乾、吞嚥困難"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01591', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關Phenylketonuria（苯酮尿症）的敘述，下列何者錯誤？', '["Phenylalaninehydroxylase酵素功能缺乏，導致苯丙胺酸（Phenylalanine）在血液中大量堆積", "孩童、青少年及成人時期皆建議遵從phenylalanine-restricted飲食", "要限制含有苯丙胺酸的食物（如：魚肉蛋奶類），可以Phenylalanine-free特殊配方進行營養 補充", "除了phenylalanine，若血中苯丙胺酸濃度過高，tyrosine亦須進行限制"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01592', 'dietitian', 'dietitian-moex-109-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '癲癇病人服用抗痙攣藥物Phenytoin可能會影響下列何種營養素在腎臟的代謝，而造成該營養素 的缺乏？', '["維生素B", "維生素D", "維生素A", "維生素C 12"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:56+00:00", "source_pdf_sha1": "91df855cb26e", "answer_pdf_sha1": "f9a188517089", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
